<span class="line"><span style="color:#CDD6F4;">                name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;project_type&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">(),</span></span>
